import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

const REGIONS = ['서울', '경기', '인천', '부산', '대구', '기타'];
const AGE_GROUPS = ['10대', '20대', '30대', '40대', '50대 이상'];
const SKILL_LEVELS = ['초보', '중급', '고수'];

const TEMPLATE = `모임 시간: 
장소: 
모인 인원: 
추가사항: `;

function PostForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [form, setForm] = useState({
    title: '',
    content: TEMPLATE,
    author: '',
    meeting_time: '',
    meeting_place: '',
    member_count: '',
    region: '',
    age_group: '',
    skill_level: '',
    extra_tags: '',
  });
  const isEdit = !!id;

  useEffect(() => {
    if (isEdit) {
      fetch(`/api/posts/${id}`)
        .then(res => res.json())
        .then(data => setForm({ ...form, ...data.post }));
    }
    // eslint-disable-next-line
  }, [id]);

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async e => {
    e.preventDefault();
    const method = isEdit ? 'PUT' : 'POST';
    const url = isEdit ? `/api/posts/${id}` : '/api/posts';
    await fetch(url, {
      method,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    navigate('/posts');
  };

  return (
    <div style={{ maxWidth: 700, margin: '40px auto', background: '#fff', borderRadius: 12, boxShadow: '0 2px 8px #bbb', padding: 32 }}>
      <h2>{isEdit ? '게시글 수정' : '게시글 작성'}</h2>
      <form onSubmit={handleSubmit}>
        <div style={{ marginBottom: 16 }}>
          <input name="title" value={form.title} onChange={handleChange} placeholder="제목" style={{ width: '100%', fontSize: 18, padding: 8 }} required />
        </div>
        <div style={{ marginBottom: 16 }}>
          <textarea name="content" value={form.content} onChange={handleChange} rows={8} style={{ width: '100%', fontSize: 16, padding: 8 }} required />
        </div>
        <div style={{ marginBottom: 16 }}>
          <input name="author" value={form.author} onChange={handleChange} placeholder="작성자" style={{ width: 200, marginRight: 12 }} required />
          <input name="meeting_time" value={form.meeting_time || ''} onChange={handleChange} placeholder="모임 시간" style={{ width: 180, marginRight: 12 }} />
          <input name="meeting_place" value={form.meeting_place || ''} onChange={handleChange} placeholder="장소" style={{ width: 180, marginRight: 12 }} />
          <input name="member_count" value={form.member_count || ''} onChange={handleChange} placeholder="모인 인원" style={{ width: 100 }} />
        </div>
        <div style={{ marginBottom: 16 }}>
          <select name="region" value={form.region || ''} onChange={handleChange} style={{ marginRight: 8 }}>
            <option value="">지역(선택 또는 직접입력)</option>
            {REGIONS.map(r => <option key={r} value={r}>{r}</option>)}
          </select>
          <input name="region" value={form.region || ''} onChange={handleChange} placeholder="직접입력" style={{ width: 120, marginRight: 8 }} />
          <select name="age_group" value={form.age_group || ''} onChange={handleChange} style={{ marginRight: 8 }}>
            <option value="">연령대(선택 또는 직접입력)</option>
            {AGE_GROUPS.map(a => <option key={a} value={a}>{a}</option>)}
          </select>
          <input name="age_group" value={form.age_group || ''} onChange={handleChange} placeholder="직접입력" style={{ width: 100, marginRight: 8 }} />
          <select name="skill_level" value={form.skill_level || ''} onChange={handleChange} style={{ marginRight: 8 }}>
            <option value="">실력(선택 또는 직접입력)</option>
            {SKILL_LEVELS.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          <input name="skill_level" value={form.skill_level || ''} onChange={handleChange} placeholder="직접입력" style={{ width: 100, marginRight: 8 }} />
        </div>
        <div style={{ marginBottom: 16 }}>
          <input name="extra_tags" value={form.extra_tags || ''} onChange={handleChange} placeholder="기타 태그(쉼표로 구분)" style={{ width: 300 }} />
        </div>
        <button type="submit" style={{ float: 'right', marginTop: 12 }}>{isEdit ? '수정 완료' : '작성 완료'}</button>
      </form>
    </div>
  );
}

export default PostForm;
